const { userMonths, userYear } = $input.first().json;

// Sort months
const months = [...userMonths].map(Number).sort((a, b) => a - b);

if (!months.length) {
    throw new Error("userMonths cannot be empty");
}

const firstMonth = months[0];
const lastMonth = months[months.length - 1];

// Start Date
const startDate =
    `${userYear}-${String(firstMonth).padStart(2, "0")}-01 00:00:00`;

// End Date = first day of next month
let endMonth = lastMonth + 1;
let endYear = userYear;

if (endMonth === 13) {
    endMonth = 1;
    endYear++;
}

const endDate =
    `${endYear}-${String(endMonth).padStart(2, "0")}-01 00:00:00`;

const query = `
SELECT
    m.content_id,
    m.content_key,
    m.content_type,
    m.content_title,
    m.external_id,
    m.status,

    DATE_FORMAT(m.created_date,'%Y-%m-%d %H:%i:%s') AS metadata_created_date,

    COALESCE(v.file_name,'') AS file_name,
    COALESCE(v.file_type,'') AS file_type,

    DATE_FORMAT(v.created_date,'%Y-%m-%d %H:%i:%s') AS video_created_date,

    CASE
        WHEN JSON_VALID(v.media_info)
        THEN COALESCE(
            JSON_UNQUOTE(JSON_EXTRACT(v.media_info,'$.encode.duration')),
            0
        )
        ELSE 0
    END AS duration

FROM media_asset.asset m

LEFT JOIN media_asset.asset v
    ON v.content_key = m.content_key
    AND v.service_id = 9001
    AND v.file_type = 'video'
    AND v.status = 'processing-success'
    AND v.created_date = (
        SELECT MAX(v2.created_date)
        FROM media_asset.asset v2
        WHERE v2.content_key = m.content_key
          AND v2.service_id = 9001
          AND v2.file_type = 'video'
          AND v2.status = 'processing-success'
    )

WHERE
    m.service_id = 9001
    AND m.file_type = 'metadata'

    AND (
        (
            LOWER(m.content_type) IN ('series','season')
            AND m.status = 'processing-not-required'
        )
        OR
        (
            LOWER(m.content_type) NOT IN ('series','season')
            AND m.status IN ('processing-success','processing-not-required')
        )
    )

    AND m.created_date >= '${startDate}'
    AND m.created_date < '${endDate}'

ORDER BY
    m.created_date;
`;

return [
    {
        json: {
            query
        }
    }
];

const items = $input.all();       // All incoming items
const batchSize = 80;
const output = [];

for (let i = 0; i < items.length; i += batchSize) {
  const batch = items.slice(i, i + batchSize);

  // Extract content_keys from this batch
  const keys = batch.map(item => item.json.content_key);

  output.push({
    json: {
      keys: keys    // array of 80 or remaining keys
    }
  });
}

return output;

// This node must be set to "Run Once for All Items"

const inputItems = $input.all();   // get all items from previous node

const combinedResults = inputItems.reduce((accumulator, currentItem) => {

  // Correct path based on your sample data
  const nestedResults = currentItem.json.results || [];

  // Map the fields you need
  const mappedResults = nestedResults.map(item => ({
    content_id: item.id,
    content_key: item.key,
    call_sign: item.l2v_cs,
    status : item.st
  }));

  // Merge into accumulator
  return accumulator.concat(mappedResults);

}, []);

// Return the final merged result
return [
  {
    json: {
      all_content_data: combinedResults
    }
  }
];

const results = $json.all_content_data;

return results.map(item => ({
  json: {
    content_id: item.content_id,
    content_key: item.content_key,
    call_sign: item.call_sign,
    vod_cms_status : item.status
  }
}));

let items = $input.all();

// 1. Total content count
let totalContent = items.length;

// 2. Total duration in seconds
let totalDurationSec = items.reduce((sum, item) => {
    return sum + Number(item.json.duration || 0);
}, 0);

// 3. Total duration in hours
let totalDurationHours = totalDurationSec / 3600;

// 4. Start with original rows
let output = [...items];

// 5. Add one empty row
output.push({
    json: {
        content_title: "",
        duration: ""
    }
});

// 6. Add summary rows

output.push({
    json: {
        content_title: "Duration in Seconds",
        duration: totalDurationSec
    }
});

output.push({
    json: {
        content_title: "Duration in Hours",
        duration: totalDurationHours
    }
});

output.push({
    json: {
        content_title: "Total Contents",
        duration: totalContent
    }
});

return output;

// Return them properly for next node
return [
  {
  "userMonths": [7],
  "userYear": 2026
  }
];
